    def executable(self):
        return os.access(self.path, os.X_OK)

    @stored_property
    def elf(self):
        return detect_elf_binary(self.path)

    @stored_property
    def hash(self):
        with open(self.path, 'rb') as f:
            return hashlib.sha256(f.read()).hexdigest()

    @stored_property
    def requires_launcher(self):

