        in_lib_directory = any(directory in self.path for directory in lib_directories)
        if in_bin_directory and not in_lib_directory:
            return True
        if in_lib_directory and not in_bin_directory:
            return False

        return re.search(r'\.so(?:\.|$)', self.path)

